#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e5+5;
struct query{int l,r;}q[N];
int T,n,sq,cnt,a[N],m,Bas;
int L,R,c[N],nowCnt,ans[N];
vector<int> g[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(query q1,query q2){
    if(q1.l/sq!=q2.l/sq)return q1.l<q2.l;
    if((q1.l/sq)&1)return q1.r<q2.r;else return q1.r>q2.r;
}
void Add(int p){if(!c[a[p]])nowCnt++;c[a[p]]++;return;}
void Del(int p){if(c[a[p]]==1)nowCnt--;c[a[p]]--;return;}
int main(){
    T=read();
    while(T--){
        n=read(),m=0,L=1,R=0;
        sq=sqrt(n),Bas=0,nowCnt=0,cnt=0;
        for(int i=1;i<=n;i++)ans[i]=0,c[i]=0;
        for(int i=1;i<=n;i++)a[i]=read(),g[a[i]].pb(i);
        for(int x=1;x<=n;x++){
            if(g[x].size()>0)Bas++;
            if(g[x].size()<2)continue;
            for(int i=0;i<g[x].size()-1;i++)
                q[++m]={g[x][i],g[x][i+1]};
        }sort(q+1,q+m+1,cmp);
        for(int i=1;i<=m;i++){
            while(L>q[i].l)Add(--L);
            while(R<q[i].r)Add(++R);
            while(L<q[i].l)Del(L++);
            while(R>q[i].r)Del(R--);
            ans[1]++,ans[nowCnt]--;
        }for(int i=1;i<=n;i++)ans[i]+=ans[i-1];
        for(int i=1;i<=n;i++)
            cout<<ans[i]+Bas<<" ";cout<<"\n";
        for(int i=1;i<=n;i++)g[i].resize(0);
    }
    return 0;
}
